  ('disabled-7c4986e7-moex-00253', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-110-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '關於廠商等產量線的敘述，下列何者正確？', '["其斜率代表邊際替代率", "線上的生產組合均為成本最小點", "斜率可以為正或負", "任兩條線不可能相交"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "bdee1ccae880", "answer_pdf_sha1": "5625f3fd9f41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "405", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00254', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-110-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '個人持有貨幣鈔券越多，財富越多。因此，中央銀行只要多印紙幣，並發 給國民即可增加全國人民實質財富。', '["正確，錢（紙幣）越多越好", "錯誤，總產出不變的條件下，增加貨幣供給只會帶來通貨膨脹，這叫合 成謬誤（Fallacyofcomposition）", "正確，國家財富是個人財富的加總，個人財富越高，國家財富也高", "錯誤，這是錯誤的因果關係（Fallacyoffalsecause）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "bdee1ccae880", "answer_pdf_sha1": "5625f3fd9f41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "405", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00255', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-110-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '下列何項論述是採用「生育之機會成本」的因素來推論？', '["婦女勞動參與率越高的國家，其生育率可能越低", "醫療費用越高的國家，其生育率可能越低", "教育費用補貼越少的國家，其生育率可能越低", "嬰幼兒托育補助越少的國家，其生育率可能越低"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "bdee1ccae880", "answer_pdf_sha1": "5625f3fd9f41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "405", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL)
